19:         getAll() {
20:           return request.cookies.getAll();
21:         },
22:         setAll(cookiesToSet, headers) {
23:           // Forward updated cookies to the request so downstream
24:           // Server Components can read the refreshed session.
25:           cookiesToSet.forEach(({ name, value }) =>
26:             request.cookies.set(name, value)
